    46→        // Register a timer for the end of the session window
    47→        long windowEnd = window.getEnd();
    48→        if (windowEnd <= ctx.getCurrentWatermark()) {
    49→            // If the watermark is already past the window end, fire immediately
    50→            return TriggerResult.FIRE;
