    18→
    19→package org.apache.flink.streaming.api.windowing.assigners;
    20→
    21→import org.apache.flink.annotation.PublicEvolving;
    22→import org.apache.flink.api.common.ExecutionConfig;
    23→import org.apache.flink.api.common.typeutils.TypeSerializer;
    24→import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
    25→import org.apache.flink.streaming.api.windowing.triggers.Trigger;
    26→import org.apache.flink.streaming.api.windowing.windows.TimeWindow;
    27→
    28→import java.time.Instant;
    29→import java.time.LocalTime;
    30→import java.time.ZoneId;
    31→import java.time.ZonedDateTime;
    32→import java.util.Collection;
    33→import java.util.Collections;
    34→
    35→/**
    36→ * A {@link MergingWindowAssigner} that windows elements into sessions based on market trading
    37→ * hours. Windows represent complete trading sessions (e.g., NYSE 09:30-16:00 ET) and can handle
    38→ * multiple markets with different trading hours and timezones.
    39→ *
    40→ * <p>Elements are assigned to the trading session that contains their timestamp. Sessions may span
    41→ * multiple calendar days (e.g., overnight futures markets) and do not overlap.
    42→ *
    43→ * <p>Example usage for NYSE trading hours (09:30-16:00 ET):
    44→ *
    45→ * <pre>{@code
    46→ * DataStream<PriceEvent> stream = ...;
    47→ * KeyedStream<PriceEvent, String> keyed = stream.keyBy(e -> e.getSymbol());
    48→ * WindowedStream<PriceEvent, String, TimeWindow> windowed =
    49→ *   keyed.window(PricingSessionWindow.forMarket("NYSE",
    50→ *     ZoneId.of("America/New_York"),
    51→ *     LocalTime.of(9, 30),
    52→ *     LocalTime.of(16, 0)));
    53→ * }</pre>
    54→ */
    55→@PublicEvolving
    56→public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    57→    private static final long serialVersionUID = 1L;
    58→
    59→    private final String marketId;
    60→    private final ZoneId timezone;
    61→    private final LocalTime sessionOpen;
    62→    private final LocalTime sessionClose;
    63→
    64→    /**
    65→     * Creates a new PricingSessionWindow for a single market.
    66→     *
    67→     * @param marketId Identifier for the market (e.g., "NYSE", "LSE")
    68→     * @param timezone The timezone of the market (e.g., ZoneId.of("America/New_York"))
    69→     * @param sessionOpen The local time when the market opens (e.g., LocalTime.of(9, 30))
    70→     * @param sessionClose The local time when the market closes (e.g., LocalTime.of(16, 0))
    71→     */
    72→    private PricingSessionWindow(
    73→            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
    74→        if (marketId == null || marketId.isEmpty()) {
    75→            throw new IllegalArgumentException("Market ID cannot be null or empty");
    76→        }
    77→        if (timezone == null) {
    78→            throw new IllegalArgumentException("Timezone cannot be null");
    79→        }
    80→        if (sessionOpen == null || sessionClose == null) {
    81→            throw new IllegalArgumentException("Session open and close times cannot be null");
    82→        }
    83→        if (!sessionOpen.isBefore(sessionClose)) {
    84→            throw new IllegalArgumentException(
    85→                    "Session open time must be before close time (for same-day sessions)");
    86→        }
    87→
    88→        this.marketId = marketId;
    89→        this.timezone = timezone;
    90→        this.sessionOpen = sessionOpen;
    91→        this.sessionClose = sessionClose;
    92→    }
    93→
    94→    /**
    95→     * Factory method to create a PricingSessionWindow for a specific market.
    96→     *
    97→     * @param marketId Identifier for the market (e.g., "NYSE", "LSE")
    98→     * @param timezone The timezone of the market
    99→     * @param sessionOpen The local time when the market opens
   100→     * @param sessionClose The local time when the market closes
   101→     * @return A new PricingSessionWindow instance
   102→     */
   103→    public static PricingSessionWindow forMarket(
   104→            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
   105→        return new PricingSessionWindow(marketId, timezone, sessionOpen, sessionClose);
   106→    }
   107→
   108→    @Override
   109→    public Collection<TimeWindow> assignWindows(
   110→            Object element, long timestamp, WindowAssignerContext context) {
   111→        // Convert the timestamp (milliseconds since epoch) to a ZonedDateTime in the market's
   112→        // timezone
   113→        ZonedDateTime elementTime =
   114→                ZonedDateTime.ofInstant(Instant.ofEpochMilli(timestamp), timezone);
   115→
   116→        // Determine the session start and end times for the element's date
   117→        ZonedDateTime sessionStart =
   118→                elementTime.toLocalDate().atTime(sessionOpen).atZone(timezone);
   119→        ZonedDateTime sessionEnd = elementTime.toLocalDate().atTime(sessionClose).atZone(timezone);
   120→
   121→        // If the element's time is before the session open, it belongs to the previous day's
   122→        // session
   123→        // (for overnight sessions like futures)
